// ─────────────────────────────────────────────
//  HELPERS
// ─────────────────────────────────────────────
function dateKey(d) {
  return `${d.getFullYear()}-${String(d.getMonth()+1).padStart(2,"0")}-${String(d.getDate()).padStart(2,"0")}`;
}
function fromKey(k) { return new Date(k + "T12:00:00"); }
function formatWeekday(d) { return d.toLocaleDateString("en-US",{weekday:"long"}); }
function formatDay(d) { return d.getDate(); }
function formatMonthYear(d) { return d.toLocaleDateString("en-US",{month:"long",year:"numeric"}); }
function formatFullDate(d) { return d.toLocaleDateString("en-US",{weekday:"long",month:"long",day:"numeric",year:"numeric"}); }
function getDatesForDefaultList() {
  const dates = [];
  for (let i = 0; i < 14; i++) {
    const d = new Date(); d.setHours(12,0,0,0);
    d.setDate(d.getDate() - i);
    dates.push(d);
  }
  return dates;
}
function buildCalGrid(year, month) {
  const firstDay = new Date(year, month, 1).getDay();
  const daysInMonth = new Date(year, month+1, 0).getDate();
  const prevDays = new Date(year, month, 0).getDate();
  const cells = [];
  for (let i = firstDay-1; i >= 0; i--) cells.push({day:prevDays-i,current:false,month:month-1,year:month===0?year-1:year});
  for (let d = 1; d <= daysInMonth; d++) cells.push({day:d,current:true,month,year});
  const rem = 42 - cells.length;
  for (let d = 1; d <= rem; d++) cells.push({day:d,current:false,month:month+1,year:month===11?year+1:year});
  return cells;
}

async function fetchArticles(dateStr) {
  const readable = fromKey(dateStr).toLocaleDateString("en-US",{month:"long",day:"numeric",year:"numeric"});
  const prompt = `Search for Buffalo Bills NFL news articles published on ${readable}.
Return a JSON object:
{"themes":["theme 1","theme 2"],"writeup":"3-5 sentence narrative summary of the day","articles":[{"title":"...","source":"...","url":"..."}]}
- themes: 2-4 short noun phrases (4-6 words max)
- writeup: a flowing 3-5 sentence editorial summary of the day's Bills news, written in an engaging sports-journalism style. Cover the main stories and their significance.
- articles: 3-8 real articles with real URLs from search results
- If none found: themes:["Quiet news day"], writeup:"No significant Bills news coverage found for this date.", articles:[{"title":"No Bills coverage found","source":"—","url":""}]
- Respond ONLY with raw JSON. No markdown, no backticks.`;
  const res = await fetch("/api/claude",{
    method:"POST", headers:{"Content-Type":"application/json"},
    body: JSON.stringify({model:"claude-sonnet-4-20250514",max_tokens:1500,
      tools:[{type:"web_search_20250305",name:"web_search"}],
      messages:[{role:"user",content:prompt}]})
  });
  const data = await res.json();
  if (!res.ok) throw new Error(data.error?.message||"API error");
  const tb = data.content?.find(b=>b.type==="text");
  if (!tb) throw new Error("No text in response");
  return JSON.parse(tb.text.replace(/```json|```/g,"").trim());
}

// Fetch grouped-by-topic article list (used on day detail page)
async function fetchGroupedArticles(dateStr) {
  const readable = fromKey(dateStr).toLocaleDateString("en-US",{month:"long",day:"numeric",year:"numeric"});
  const prompt = `Search for all Buffalo Bills NFL news articles published on ${readable}.

Group them by major topic and return ONLY this JSON shape:
{
  "themes": ["short theme 1","short theme 2","short theme 3"],
  "topics": [
    {
      "heading": "Topic Name",
      "articles": [
        {"title":"Article headline","source":"Publication","url":"https://..."}
      ]
    }
  ]
}

Rules:
- topics: 2-6 groups based on the main storylines of the day (e.g. "Roster Moves", "Injury Report", "Stadium News", "Josh Allen", "Draft Analysis")
- Each topic should have 1-5 articles
- Only use real URLs actually found in search results
- themes: 2-4 short noun phrases summarizing the day overall
- If no Bills news found: themes:["Quiet news day"], topics:[{"heading":"No Coverage Found","articles":[{"title":"No Bills news articles found for this date","source":"—","url":""}]}]
- Respond ONLY with raw JSON. No markdown, no backticks, no explanation.`;
  const res = await fetch("/api/claude",{
    method:"POST", headers:{"Content-Type":"application/json"},
    body: JSON.stringify({model:"claude-sonnet-4-20250514",max_tokens:2000,
      tools:[{type:"web_search_20250305",name:"web_search"}],
      messages:[{role:"user",content:prompt}]})
  });
  const data = await res.json();
  if (!res.ok) throw new Error(data.error?.message||"API error");
  const tb = data.content?.find(b=>b.type==="text");
  if (!tb) throw new Error("No text in response");
  return JSON.parse(tb.text.replace(/```json|```/g,"").trim());
}

// Convert seeded flat articles into grouped format for detail page
function groupSeededArticles(data) {
  if (!data) return null;
  if (data.topics) return data; // already grouped
  // Auto-group flat articles by theme chips
  const articles = data.articles || [];
  const themes = data.themes || [];
  if (articles.length === 0) return { themes, topics: [] };
  // Assign articles to topics based on themes; overflow into "General Coverage"
  const perTopic = Math.ceil(articles.length / Math.max(themes.length, 1));
  const topics = themes.map((heading, i) => ({
    heading,
    articles: articles.slice(i * perTopic, (i + 1) * perTopic)
  })).filter(t => t.articles.length > 0);
  // Leftover
  const used = topics.reduce((n,t)=>n+t.articles.length,0);
  if (used < articles.length) {
    topics.push({ heading: "General Coverage", articles: articles.slice(used) });
  }
  return { themes, topics };
}

