function DayDetailPage({ dateKey: key, seededCache, onBack }) {
  const date = fromKey(key);
  const [data, setData] = useState(() => seededCache || null);
  const [loading, setLoading] = useState(!seededCache);
  const [error, setError] = useState(null);

  async function load() {
    setLoading(true); setError(null);
    try {
      const result = await fetchArticles(key);
      setData(result);
    } catch(e) { setError(e.message); }
    finally { setLoading(false); }
  }

  // If no seeded data, auto-fetch on mount
  useState(() => { if (!seededCache) load(); }, []);

  const articles = data?.articles || [];

  return (
    <main className="container">
      <button className="detail-back" onClick={onBack}>← Back to Archive</button>

      <div className="detail-hero">
        <div className="detail-weekday">{formatWeekday(date)}</div>
        <div className="detail-date-big">
          {date.toLocaleDateString("en-US",{month:"long",day:"numeric"})}
        </div>
        <div className="detail-year">{date.getFullYear()}</div>
      </div>

      {loading && (
        <div className="detail-loading">
          <div className="spinner" />
          Searching Bills archive for {formatFullDate(date)}…
        </div>
      )}
      {error && (
        <div>
          <div className="detail-error">Failed to load: {error}</div>
          <button className="detail-refresh" onClick={load}>↻ Retry</button>
        </div>
      )}
      {data && !loading && (
        <>
          {data.writeup && (
            <p className="detail-writeup">{data.writeup}</p>
          )}
          {data.articles && data.articles.length > 0 && data.articles[0].title !== "No Bills coverage found" && (
            <div className="articles-label">Coverage from this day</div>
          )}
          <ul className="topic-articles">
            {articles.map((a, ai) => (
              <li key={ai} className="topic-article-item">
                <div className="topic-bullet" />
                {a.url
                  ? <a className="topic-link" href={a.url} target="_blank" rel="noopener noreferrer">{a.title}</a>
                  : <span className="topic-link" style={{cursor:"default",color:MUTED}}>{a.title}</span>
                }
                <span className="topic-source">{a.source}</span>
              </li>
            ))}
          </ul>
          <button className="detail-refresh" onClick={load} style={{marginTop:16}}>↻ Refresh from web</button>
        </>
      )}
    </main>
  );
}


