async function fetchSearchResults(query) {
  const prompt = `Search for Buffalo Bills NFL news and history related to: "${query}"

Find the most relevant dates and articles. Return ONLY this JSON:
{
  "results": [
    {
      "date": "YYYY-MM-DD",
      "relevance": "One sentence explaining why this date is relevant to the search",
      "articles": [
        {"title": "Article headline", "source": "Publication", "url": "https://..."}
      ]
    }
  ]
}
Rules:
- results: 3-8 most relevant dates, newest first
- Each result needs a real date and at least 1 real article URL from search results
- relevance: short plain-English explanation of connection to the query
- Respond ONLY with raw JSON. No markdown, no backticks.`;

  const res = await fetch("/api/claude", {
    method:"POST", headers:{"Content-Type":"application/json"},
    body: JSON.stringify({model:"claude-sonnet-4-20250514", max_tokens:2000,
      tools:[{type:"web_search_20250305",name:"web_search"}],
      messages:[{role:"user",content:prompt}]})
  });
  const data = await res.json();
  if (!res.ok) throw new Error(data.error?.message||"API error");
  const tb = data.content?.find(b=>b.type==="text");
  if (!tb) throw new Error("No text in response");
  return JSON.parse(tb.text.replace(/```json|```/g,"").trim());
}

function highlight(text, query) {
  if (!query) return text;
  const parts = text.split(new RegExp(`(${query.replace(/[.*+?^${}()|[\]\\]/g,'\\$&')})`, 'gi'));
  return parts.map((p,i) => p.toLowerCase()===query.toLowerCase()
    ? <mark key={i} className="search-match">{p}</mark> : p);
}

