// ─────────────────────────────────────────────
//  ROOT APP
// ─────────────────────────────────────────────
export default function App() {
  const today = new Date(); today.setHours(12,0,0,0);
  const [page, setPage] = useState("home"); // "home"|"day"|"search"|"current"|"ex"|"creators"
  const [selectedKey, setSelectedKey] = useState(null);
  const [searchQuery, setSearchQuery] = useState("");
  const [cache, setCache] = useState({...SEEDED});

  function goToDay(key) { setSelectedKey(key); setPage("day"); window.scrollTo(0,0); }
  function goHome() { setPage("home"); window.scrollTo(0,0); }
  function goSearch(q) { if(!q){setPage("home");return;} setSearchQuery(q); setPage("search"); window.scrollTo(0,0); }
  function goNav(id) { setPage(id); window.scrollTo(0,0); }

  const navPage = ["home","schedule","creators"].includes(page) ? page : "home";

  return (
    <>
      <style>{style}</style>
      <Masthead onHome={goHome} today={today} onSearch={goSearch} />
      <NavBar page={navPage} onNav={goNav} />
      {page === "home"    && <HomePage cache={cache} setCache={setCache} onDaySelect={goToDay} />}
      {page === "day"     && <DayDetailPage dateKey={selectedKey} seededCache={cache[selectedKey]} onBack={goHome} />}
      {page === "search"  && <SearchPage query={searchQuery} onDaySelect={goToDay} onBack={goHome} />}
      {page === "current" && <CurrentPlayersPage />}
      {page === "ex"      && <ExPlayersPage />}
      {page === "creators"&& <ContentCreatorsPage />}
      {page === "schedule"&& <SchedulePage />}
    </>
  );
}
